<template>
	<div class="container pt-md-5">
		<h1 class="mb-4 mt-4 mt-md-0 text-left danse-jump-container">
			<span class="text-primary" :ref="addJumpElement">M</span>
			<span :ref="addJumpElement">y&nbsp;</span>
			<span :ref="addJumpElement">w</span>
			<span :ref="addJumpElement">o</span>
			<span :ref="addJumpElement">r</span>
			<span :ref="addJumpElement">k</span>
			<span :ref="addJumpElement">s</span>
		</h1>
		<section>
			<nav class="type mb-4">
				<ul class="d-flex">
					<li
						v-for="(t, i) in projectTypes"
						:key="i"
						class="mr-3"
						:class="filterClass(t)"
						@click="onFiltering(t)"
					>
						{{ t }}
					</li>
				</ul>
			</nav>

			<div class="projects row">
				<transition-group
					name="project"
					tag="div"
					v-for="(works_by_cols, i) in $helper.groupByN(works, columns)"
					:key="i"
					class="p-0"
					:class="setColumns()"
					appear
				>
					<Project v-for="work in works_by_cols" :key="`${work.name}`" :work="work" class="project-item" />
				</transition-group>
			</div>
		</section>
	</div>
</template>

<script>
	import works from '@/works.json';
	import Project from '@/components/works/Project';
	import danseMixin from '../mixins/danseMixin';

	export default {
		mixins: [danseMixin],
		components: {
			Project,
		},
		data() {
			return {
				projectTypes: ['all', 'school', 'professional', 'personal'],
				works: works,
				columns: null,
			};
		},
		methods: {
			filterClass(projectType) {
				if (!this.$route.query.type && projectType === 'all') return 'active';
				if (this.$route.query.type === projectType) return 'active';
				return '';
			},
			onFiltering(projectType) {
				this.$router.push({ query: { type: projectType } });
				this.works = this.$helper.filter((w) => (projectType === 'all' ? true : w.type === projectType), works);
			},
			getBreakPoint(width) {
				if (width < 768) return 'sm';
				if (width < 992) return 'md';
				if (width < 1200) return 'lg';
				return 'xl';
			},
			setColumns() {
				const bp = this.getBreakPoint(window.innerWidth);
				if (bp === 'sm' || bp === 'md') this.columns = 2;
				else this.columns = 3;
				return 'col-lg-4 col-6';
			},
		},
		beforeMount() {
			window.addEventListener('resize', this.setColumns);
			this.setColumns();
			this.onFiltering(this.$route.query.type || 'all');
		},
		beforeUnmount() {
			window.removeEventListener('resize', this.setColumns);
		},
	};
</script>

